// ProRated logo — transparent PNG, black background removed
const LOGO_SRC = "data:image/png;base64,";

export default function Logo({ size = 40, showWordmark = false, dark = false }) {
  if (showWordmark) {
    return (
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 2 }}>
        <img
          src={LOGO_SRC}
          alt="ProRated"
          width={size}
          height={size}
          style={{ flexShrink: 0, display: "block", objectFit: "contain" }}
        />
        <div style={{
          fontFamily: "'Georgia', 'Times New Roman', serif",
          fontWeight: 700,
          fontSize: size * 0.28,
          letterSpacing: "0.06em",
          color: dark ? "#fff" : "#1a3328",
          lineHeight: 1,
          textTransform: "uppercase",
        }}>
          Pro<span style={{ color: "#c8831a" }}>Rated</span>
        </div>
      </div>
    );
  }

  return (
    <img
      src={LOGO_SRC}
      alt="ProRated"
      width={size}
      height={size}
      style={{ flexShrink: 0, display: "block", objectFit: "contain" }}
    />
  );
}
